SET NAMES utf8mb4;
USE `my_blog`;
START TRANSACTION;



UPDATE `blog_article_tag` SET `deleted_at`='2026-05-10 17:47:34',`updated_at`='2026-05-10 17:47:34' WHERE `article_id` IN (630000, 630001, 630002, 630003, 630004, 630005, 630006, 630007, 630008, 630009, 630010, 630011, 630012, 630013, 630014, 630015, 630016, 630017, 630018, 630019, 630020, 630021, 630022, 630023, 630024, 630025, 630026, 630027, 630028, 630029, 630030, 630031, 630032, 630033, 630034, 630035, 630036, 630037, 630038, 630039, 630040, 630041, 630042, 630043, 630044);


UPDATE `blog_column_article` SET `deleted_at`='2026-05-10 17:47:34',`updated_at`='2026-05-10 17:47:34' WHERE `column_id`=9600011;
UPDATE `blog_topic_article` SET `deleted_at`='2026-05-10 17:47:34',`updated_at`='2026-05-10 17:47:34' WHERE `topic_id`=9700011;

UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg INNER JOIN `blog_article` a ON a.`id` = atg.`article_id` WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE t.`name` IN ('PostgreSQL', '数据库', 'SQL', '关系型数据库');
UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE c.`id` = 9600011;
UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED' AND a.`deleted_at` IS NULL) WHERE t.`id` = 9700011;
COMMIT;
